const input = $input.first().json;
const amount = Math.min(Math.max(parseInt(input.amount) || 1, 1), 10);
const difficulty = input.difficulty || '';
const category = input.category || '';

// Category mapping
const categories = {
  'general': 9, 'books': 10, 'film': 11, 'music': 12, 'theatre': 13,
  'television': 14, 'tv': 14, 'video games': 15, 'board games': 16,
  'science': 17, 'science nature': 17, 'computers': 18, 'computer': 18,
  'mathematics': 19, 'math': 19, 'mythology': 20, 'sports': 21,
  'geography': 22, 'history': 23, 'politics': 24, 'art': 25,
  'celebrities': 26, 'animals': 27, 'vehicles': 28, 'comics': 29,
  'gadgets': 30, 'anime': 31, 'manga': 31, 'cartoons': 32, 'cartoon': 32
};

let url = 'https://opentdb.com/api.php?amount=' + amount;

if (difficulty && ['easy', 'medium', 'hard'].includes(difficulty.toLowerCase())) {
  url += '&difficulty=' + difficulty.toLowerCase();
}

if (category) {
  const catId = categories[category.toLowerCase()];
  if (catId) url += '&category=' + catId;
}

try {
  const data = await helpers.httpRequest({ method: 'GET', url });

  if (data.response_code !== 0) {
    const errors = {
      1: 'Not enough questions available for these filters. Try fewer questions or different category/difficulty.',
      2: 'Invalid category or difficulty parameter.',
      5: 'Rate limit exceeded. Please wait a moment.'
    };
    return [{ json: { error: errors[data.response_code] || 'API error (code ' + data.response_code + ')' } }];
  }

  // Decode HTML entities
  function decode(str) {
    return str.replace(/&quot;/g, '"').replace(/&#039;/g, "'").replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&eacute;/g, 'e').replace(/&ouml;/g, 'oe').replace(/&uuml;/g, 'ue').replace(/&auml;/g, 'ae').replace(/&szlig;/g, 'ss').replace(/&ldquo;/g, '"').replace(/&rdquo;/g, '"').replace(/&lsquo;/g, "'").replace(/&rsquo;/g, "'").replace(/&hellip;/g, '...');
  }

  let result = '';
  data.results.forEach((q, i) => {
    const num = amount > 1 ? (i + 1) + '. ' : '';
    result += num + decode(q.question) + '\n';
    result += '  Category: ' + decode(q.category) + '\n';
    result += '  Difficulty: ' + q.difficulty + '\n';

    if (q.type === 'boolean') {
      result += '  Type: True/False\n';
    } else {
      // Shuffle answers
      const answers = [...q.incorrect_answers.map(decode), decode(q.correct_answer)];
      for (let j = answers.length - 1; j > 0; j--) {
        const k = Math.floor(Math.random() * (j + 1));
        [answers[j], answers[k]] = [answers[k], answers[j]];
      }
      const letters = ['A', 'B', 'C', 'D'];
      answers.forEach((a, idx) => {
        result += '  ' + letters[idx] + ') ' + a + '\n';
      });
    }

    result += '  Answer: ' + decode(q.correct_answer) + '\n\n';
  });

  return [{ json: { result: result.trim() } }];

} catch (err) {
  return [{ json: { error: 'Failed to fetch trivia: ' + err.message } }];
}
